#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Basename qw(dirname);
use Cwd qw(getcwd);

my $MINIGIT_DIR = ".minigit";
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $COMMITS_DIR = "$MINIGIT_DIR/commits";
my $INDEX_FILE  = "$MINIGIT_DIR/index";
my $HEAD_FILE   = "$MINIGIT_DIR/HEAD";

sub minihash {
    my ($data) = @_;
    # Use Math::BigInt to handle 64-bit unsigned arithmetic
    # Actually, Perl can handle 64-bit integers natively on 64-bit systems
    # But we need to be careful with unsigned overflow
    use integer;
    my $h = 1469598103934665603;
    # We need unsigned 64-bit math, so we'll use no integer and handle manually
    no integer;

    # Use vec or manual bit ops. Perl's integers on 64-bit are fine for XOR
    # but multiplication needs modular arithmetic.
    # Let's use the & 0xFFFFFFFFFFFFFFFF mask approach.
    my $mask = 0xFFFFFFFFFFFFFFFF;
    $h = 1469598103934665603;

    my @bytes = unpack("C*", $data);
    for my $b (@bytes) {
        $h = ($h ^ $b) & $mask;
        # Multiply by 1099511628211, mod 2^64
        # On 64-bit Perl this may overflow to float. Use repeated shift+add.
        # 1099511628211 = 0x100000001B3
        # h * 0x100000001B3 = h * 2^40 + h * 0x1B3
        # 0x1B3 = 435
        my $lo = ($h * 435) & $mask;
        my $hi = ($h << 40) & $mask;
        $h = ($lo + $hi) & $mask;
    }

    return sprintf("%016x", $h);
}

sub read_file {
    my ($path) = @_;
    open my $fh, '<', $path or return "";
    local $/;
    my $content = <$fh>;
    close $fh;
    return defined $content ? $content : "";
}

sub read_file_raw {
    my ($path) = @_;
    open my $fh, '<:raw', $path or return "";
    local $/;
    my $content = <$fh>;
    close $fh;
    return defined $content ? $content : "";
}

sub write_file {
    my ($path, $content) = @_;
    open my $fh, '>', $path or die "Cannot write $path: $!\n";
    print $fh $content;
    close $fh;
}

sub write_file_raw {
    my ($path, $content) = @_;
    open my $fh, '>:raw', $path or die "Cannot write $path: $!\n";
    print $fh $content;
    close $fh;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path($OBJECTS_DIR);
    make_path($COMMITS_DIR);
    write_file($INDEX_FILE, "");
    write_file($HEAD_FILE, "");
}

sub cmd_add {
    my ($file) = @_;
    if (!defined $file || !-e $file) {
        print "File not found\n";
        exit 1;
    }

    my $content = read_file_raw($file);
    my $hash = minihash($content);

    write_file_raw("$OBJECTS_DIR/$hash", $content);

    # Read current index
    my $index_content = read_file($INDEX_FILE);
    my @lines = grep { $_ ne '' } split(/\n/, $index_content);

    # Add if not already present
    unless (grep { $_ eq $file } @lines) {
        push @lines, $file;
    }

    write_file($INDEX_FILE, join("\n", @lines) . "\n");
}

sub cmd_commit {
    my ($message) = @_;

    my $index_content = read_file($INDEX_FILE);
    my @files = grep { $_ ne '' } split(/\n/, $index_content);

    if (!@files) {
        print "Nothing to commit\n";
        exit 1;
    }

    @files = sort @files;

    my $head = read_file($HEAD_FILE);
    chomp $head if defined $head;
    my $parent = (defined $head && $head ne '') ? $head : "NONE";

    my $timestamp = time();

    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";

    for my $file (@files) {
        my $blob_content = read_file_raw($file);
        my $blob_hash = minihash($blob_content);
        $commit_content .= "$file $blob_hash\n";
    }

    my $commit_hash = minihash($commit_content);

    write_file("$COMMITS_DIR/$commit_hash", $commit_content);
    write_file($HEAD_FILE, $commit_hash);
    write_file($INDEX_FILE, "");

    print "Committed $commit_hash\n";
}

sub cmd_log {
    my $head = read_file($HEAD_FILE);
    chomp $head if defined $head;

    if (!defined $head || $head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    while ($current ne "NONE" && $current ne '') {
        my $commit_content = read_file("$COMMITS_DIR/$current");
        my ($parent, $timestamp, $message);

        for my $line (split(/\n/, $commit_content)) {
            if ($line =~ /^parent: (.*)/) {
                $parent = $1;
            } elsif ($line =~ /^timestamp: (.*)/) {
                $timestamp = $1;
            } elsif ($line =~ /^message: (.*)/) {
                $message = $1;
            }
        }

        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";
        print "\n" if defined $parent && $parent ne "NONE";

        $current = $parent // "NONE";
    }
}

# Main
my $command = shift @ARGV;

if (!defined $command) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($command eq 'init') {
    cmd_init();
} elsif ($command eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($command eq 'commit') {
    # Parse -m "message"
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    if (!defined $flag || $flag ne '-m' || !defined $message) {
        print "Usage: minigit commit -m \"<message>\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($command eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $command\n";
    exit 1;
}

